const raw = $('Claude → Analyze Deployments').first().json.content?.[0]?.text || '{}';

let parsed = {};
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { raw_analysis: raw };
}

return [{ json: {
  status: 'completed',
  workflow: '13_deployment_monitor',
  deployment_count: parsed.total_deployments || 0,
  failed_count: parsed.failed || 0,
  successful_count: parsed.successful || 0,
  summary: parsed.summary || 'Analysis complete',
  analysis: parsed,
  completedAt: new Date().toISOString()
} }];
